const rawContentLines = rawArticleContent.replace(/\r\n/g, "\n").split("\n");
const rawFaqStartIndex = rawContentLines.findIndex((line) => line.trim() === "Commonly Asked Questions Regarding Autism");
const rawConsultationIndex = rawContentLines.findIndex((line) => line.trim() === "Schedule a consultation");

const visibleArticleLines =
  rawFaqStartIndex >= 0 ? rawContentLines.slice(0, rawFaqStartIndex) : rawContentLines;

const consultationArticleLines =
  rawConsultationIndex >= 0 ? rawContentLines.slice(rawConsultationIndex) : [];

const rawFaqLines =
  rawFaqStartIndex >= 0 && rawConsultationIndex > rawFaqStartIndex
    ? rawContentLines.slice(rawFaqStartIndex + 1, rawConsultationIndex)
    : [];

function buildRawFaqs(lines) {
  const items = [];
  let current = null;

  lines.forEach((line) => {
    const text = line.trim();

    if (!text) {
      return;
    }

    if (text.endsWith("?")) {
      if (current) {
        items.push(current);
      }
      current = { question: text, answer: [] };
      return;
    }

    if (current) {
      current.answer.push(line.trimEnd());
    }
  });

  if (current) {
    items.push(current);
  }

  return items;
}

const rawFaqs = buildRawFaqs(rawFaqLines);

