function FaqAccordion({ openFaq, setOpenFaq }) {
  return (
    <section id="faqs" className="mt-9">
      <div className="mb-4 flex items-center gap-4">
        <h2 className="text-[20px] font-black text-[#17111f]">Commonly Asked Questions Regarding Autism</h2>
        <div className="hidden h-px flex-1 bg-[#eadff1] sm:block"></div>
      </div>
      <div className="overflow-hidden rounded-lg border border-[#eadff1] bg-white">
        {rawFaqs.map((faq, index) => (
          <div key={faq.question} className="border-b border-[#eadff1] last:border-b-0">
            <button
              type="button"
              onClick={() => setOpenFaq(openFaq === index ? null : index)}
              className="flex w-full items-center justify-between gap-4 px-4 py-3 text-left text-[13px] font-black text-[#21142d]"
              aria-expanded={openFaq === index}
            >
              {faq.question}
              <ChevronDown
                className={`h-4 w-4 shrink-0 text-[#7835A4] transition-transform ${
                  openFaq === index ? "rotate-180" : ""
                }`}
              />
            </button>
            {openFaq === index && (
              <div className="space-y-3 px-4 pb-4 text-[12.5px] font-semibold leading-6 text-[#5f5367]">
                {faq.answer.map((answerLine, answerIndex) => (
                  <p key={answerIndex} style={{ whiteSpace: "pre-wrap" }}>
                    {answerLine}
                  </p>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </section>
  );
}

function RawArticleContent({ openFaq, setOpenFaq }) {
  const usedHeadingIds = new Set();

  const renderLine = (line, index, keyPrefix = "line") => {
    const text = line.trimEnd();
    const trimmedText = text.trim();

    if (!trimmedText) {
      return <div key={`${keyPrefix}-${index}`} className="h-2" aria-hidden="true" />;
    }

    if (index === 0 && keyPrefix === "line") {
      return (
        <h2 key={`${keyPrefix}-${index}`} className="text-[22px] font-black leading-snug text-[#17111f] sm:text-[26px]" style={{ whiteSpace: "pre-wrap" }}>
          {text}
        </h2>
      );
    }

    if (trimmedText.endsWith("?") || nonQuestionHeadings.has(trimmedText)) {
      const headingId = headingIds.get(trimmedText);
      const id = headingId && !usedHeadingIds.has(headingId) ? headingId : undefined;
      if (id) {
        usedHeadingIds.add(id);
      }

      return (
        <React.Fragment key={`${keyPrefix}-${index}`}>
          <h3 id={id} className="scroll-mt-28 pt-4 text-[18px] font-black leading-snug text-[#17111f]" style={{ whiteSpace: "pre-wrap" }}>
            {text}
          </h3>
          <VisualBlock heading={trimmedText} />
        </React.Fragment>
      );
    }

    return (
      <p key={`${keyPrefix}-${index}`} style={{ whiteSpace: "pre-wrap" }}>
        {text}
      </p>
    );
  };

  return (
    <section id="what-is-autism" className="mt-8 space-y-3 text-[14px] font-semibold leading-7 text-[#51465a]">
      {visibleArticleLines.map((line, index) => renderLine(line, index))}
      <FaqAccordion openFaq={openFaq} setOpenFaq={setOpenFaq} />
      {consultationArticleLines.map((line, index) => renderLine(line, index, "consultation"))}
    </section>
  );
}

